def sqrt_2_convergents(n: int):
    """
    Generator for the first n convergents of sqrt(2).
    """
    num, den = 3, 2
    for _ in range(n):
        yield num, den
        num, den = num + 2 * den, num + den

def solution(n: int = 1000) -> int:
    """
    Calculates the count using the generator and a generator expression.
    """
    return sum(1 for n, d in sqrt_2_convergents(n) if len(str(n)) > len(str(d)))


if __name__ == "__main__":
    print(solution(1000))
